import { resolve } from 'path'
import { defineConfig, externalizeDepsPlugin } from 'electron-vite'
import react from '@vitejs/plugin-react'
import tailwindcss from '@tailwindcss/vite'

export default defineConfig({
  main: {
    plugins: [externalizeDepsPlugin()]
  },
  preload: {
    plugins: [externalizeDepsPlugin()]
  },
  renderer: {
    resolve: {
      alias: {
        '@': resolve('src/renderer/src')
      }
    },
    plugins: [react(), tailwindcss()]
  }
})

import { app, BrowserWindow, ipcMain, nativeTheme } from 'electron'
import { join } from 'path'
import { PiSDKBridge } from './pi-sdk-bridge'
import * as sessionService from './session-service'
import type { SessionInfo, ForkableMessage, ForkPoint } from '../renderer/src/types/session'

let mainWindow: BrowserWindow | null = null
let piBridge: PiSDKBridge | null = null
let initialSessionPath: string | undefined

function createWindow(): void {
  mainWindow = new BrowserWindow({
    width: 1200,
    height: 800,
    backgroundColor: '#ffffff',
    titleBarStyle: 'hiddenInset',
    show: false,
    webPreferences: {
      preload: join(__dirname, '../preload/index.js'),
      sandbox: false
    }
  })

  mainWindow.on('ready-to-show', () => {
    mainWindow?.show()
  })

  mainWindow.on('closed', () => {
    mainWindow = null
  })

  if (process.env.ELECTRON_RENDERER_URL) {
    mainWindow.loadURL(process.env.ELECTRON_RENDERER_URL)
  } else {
    mainWindow.loadFile(join(__dirname, '../renderer/index.html'))
  }
}

function broadcastToRenderers(channel: string, data: unknown): void {
  BrowserWindow.getAllWindows().forEach((win) => {
    if (!win.isDestroyed() && !win.webContents.isDestroyed()) {
      try {
        win.webContents.send(channel, data)
      } catch {}
    }
  })
}

function initPiBridge(sessionPath?: string): void {
  piBridge = new PiSDKBridge()
  initialSessionPath = sessionPath

  piBridge.on('event', (data: unknown) => {
    // In SDK mode, extension_ui_request arrives as a regular event
    if (typeof data === 'object' && data !== null) {
      const obj = data as Record<string, unknown>
      if (obj.type === 'extension_ui_request') {
        broadcastToRenderers('pi:extensionUiRequest', data)
        return
      }
    }
    broadcastToRenderers('pi:event', data)
  })

  piBridge.on('response', (data: unknown) => {
    broadcastToRenderers('pi:response', data)
  })

  piBridge.on('connected', () => {
    broadcastToRenderers('pi:stateChanged', { connected: true })
  })

  piBridge.on('disconnected', () => {
    broadcastToRenderers('pi:stateChanged', { connected: false })
  })

  piBridge.on('error', (err: Error) => {
    console.error('[PiSDKBridge]', err.message)
  })
}

function registerIpcHandlers(): void {
  ipcMain.handle('pi:sendCommand', (_event, command: Record<string, unknown>) => {
    if (!piBridge?.isConnected) return { ok: false, error: 'Pi not connected' }
    piBridge.sendCommand(command)
    return { ok: true }
  })

  ipcMain.handle('pi:sendExtensionUIResponse', (_event, response: Record<string, unknown>) => {
    if (!piBridge?.isConnected) return { ok: false, error: 'Pi not connected' }
    piBridge.sendExtensionUIResponse(response)
    return { ok: true }
  })

  ipcMain.handle('pi:getState', () => {
    return { connected: piBridge?.isConnected ?? false }
  })

  ipcMain.handle('pi:start', async () => {
    if (!piBridge) {
      let mainSession = sessionService.findMainSession(process.cwd())
      if (mainSession && !mainSession.name) {
        sessionService.nameSession(mainSession.filePath, 'main')
        mainSession = { ...mainSession, name: 'main' }
      }
      initPiBridge(mainSession?.filePath)
    }
    try {
      await piBridge!.start(process.cwd(), initialSessionPath)
      const mainSession = sessionService.findMainSession(process.cwd())
      if (!mainSession || !mainSession.name) {
        try {
          await piBridge!.sendRpcCommand({ type: 'set_session_name', name: 'main' })
        } catch {}
        const sessionPath = piBridge!.sessionFilePath
        if (sessionPath) {
          sessionService.nameSession(sessionPath, 'main', process.cwd())
        }
      }
      return { ok: true }
    } catch (err: unknown) {
      return { ok: false, error: err instanceof Error ? err.message : String(err) }
    }
  })

  ipcMain.handle('pi:stop', async () => {
    try {
      await piBridge?.stop()
      return { ok: true }
    } catch (err: unknown) {
      return { ok: false, error: err instanceof Error ? err.message : String(err) }
    }
  })

  ipcMain.handle('session:listSessions', async () => {
    let currentPath: string | undefined
    try {
      const data = (await piBridge!.sendRpcCommand({ type: 'get_state' })) as Record<string, unknown>
      if (typeof data.sessionFile === 'string') currentPath = data.sessionFile
    } catch {
      currentPath = undefined
    }
    return sessionService.listSessions(currentPath)
  })

  ipcMain.handle('session:getForkMessages', async () => {
    try {
      const data = (await piBridge!.sendRpcCommand({ type: 'get_fork_messages' })) as {
        messages?: ForkableMessage[]
      }
      return data.messages ?? []
    } catch {
      return []
    }
  })

  ipcMain.handle('session:forkAtEntry', async (_event, entryId: string, name?: string) => {
    let parentPath: string | null = null
    try {
      const preState = (await piBridge!.sendRpcCommand({ type: 'get_state' })) as Record<string, unknown>
      parentPath = typeof preState.sessionFile === 'string' ? preState.sessionFile : null
    } catch {}

    try {
      const data = (await piBridge!.sendRpcCommand({ type: 'fork', entryId })) as Record<string, unknown>

      if (name) {
        try {
          await piBridge!.sendRpcCommand({ type: 'set_session_name', name })
        } catch {}
        try {
          const postState = (await piBridge!.sendRpcCommand({ type: 'get_state' })) as Record<string, unknown>
          const childPath = typeof postState.sessionFile === 'string' ? postState.sessionFile : null
          if (childPath) {
            sessionService.nameSession(childPath, name)
          }
        } catch {}
      }

      if (parentPath) {
        sessionService.addForkPoint(parentPath, entryId, name ?? '')
      }

      return { success: true, text: typeof data.text === 'string' ? data.text : undefined }
    } catch (err: unknown) {
      return { success: false, error: err instanceof Error ? err.message : String(err) }
    }
  })

  ipcMain.handle('session:switchSession', async (_event, sessionPath: string) => {
    try {
      await piBridge!.sendRpcCommand({ type: 'switch_session', sessionPath })
      return { success: true }
    } catch (err: unknown) {
      return { success: false, error: err instanceof Error ? err.message : String(err) }
    }
  })

  ipcMain.handle('session:newSession', async (_event, parentSessionPath?: string) => {
    try {
      const command: Record<string, unknown> = { type: 'new_session' }
      if (parentSessionPath) {
        command.parentSession = parentSessionPath
      }
      await piBridge!.sendRpcCommand(command)
      return { success: true }
    } catch (err: unknown) {
      return { success: false, error: err instanceof Error ? err.message : String(err) }
    }
  })

  ipcMain.handle('session:renameSession', async (_event, name: string) => {
    try {
      await piBridge!.sendRpcCommand({ type: 'set_session_name', name })
    } catch {}

    try {
      const data = (await piBridge!.sendRpcCommand({ type: 'get_state' })) as Record<string, unknown>
      const sessionPath = typeof data.sessionFile === 'string' ? data.sessionFile : null
      if (sessionPath) {
        sessionService.nameSession(sessionPath, name)
      }
    } catch {}

    return { success: true }
  })

  ipcMain.handle('session:getCurrentSession', async () => {
    try {
      const data = (await piBridge!.sendRpcCommand({ type: 'get_state' })) as Record<string, unknown>
      const sessionPath = typeof data.sessionFile === 'string' ? data.sessionFile : null
      if (!sessionPath) return null

      const result = sessionService.listSessions()
      for (const project of result.projects) {
        const found = project.allSessions.find((s) => s.filePath === sessionPath)
        if (found) return found
      }
      return null
    } catch {
      return null
    }
  })

  ipcMain.handle('session:refreshSessions', async () => {
    let currentPath: string | undefined
    try {
      const data = (await piBridge!.sendRpcCommand({ type: 'get_state' })) as Record<string, unknown>
      if (typeof data.sessionFile === 'string') currentPath = data.sessionFile
    } catch {
      currentPath = undefined
    }
    return sessionService.listSessions(currentPath)
  })

  ipcMain.handle('session:getMessages', async () => {
    try {
      const data = (await piBridge!.sendRpcCommand({ type: 'get_messages' })) as { messages?: unknown[] }
      return data.messages ?? []
    } catch {
      return []
    }
  })

  ipcMain.handle('session:deleteSession', async (_event, sessionPath: string) => {
    try {
      const stateData = (await piBridge!.sendRpcCommand({ type: 'get_state' })) as Record<string, unknown>
      const currentPath = typeof stateData.sessionFile === 'string' ? stateData.sessionFile : null
      if (currentPath === sessionPath) {
        return { success: false, error: 'Cannot delete the active session' }
      }
    } catch {}

    const result = sessionService.deleteSession(sessionPath)
    if (result) {
      return { success: true }
    }
    return { success: false, error: 'Failed to delete session' }
  })

  ipcMain.handle('session:getForkPoints', async (_event, sessionPath: string) => {
    return sessionService.getForkPoints(sessionPath)
  })

  ipcMain.handle('session:clearSession', async () => {
    try {
      const stateData = (await piBridge!.sendRpcCommand({ type: 'get_state' })) as Record<string, unknown>
      const oldPath = typeof stateData.sessionFile === 'string' ? stateData.sessionFile : null
      const sessionName = typeof stateData.sessionName === 'string' ? stateData.sessionName : null

      if (!oldPath) {
        return { success: false, error: 'No active session to clear' }
      }

      await piBridge!.sendRpcCommand({ type: 'new_session' })

      const newName = sessionName ?? 'main'
      try {
        await piBridge!.sendRpcCommand({ type: 'set_session_name', name: newName })
      } catch {}

      const postState = (await piBridge!.sendRpcCommand({ type: 'get_state' })) as Record<string, unknown>
      const newPath = typeof postState.sessionFile === 'string' ? postState.sessionFile : null
      if (newPath) {
        sessionService.nameSession(newPath, newName)
      }

      sessionService.deleteSession(oldPath)

      return { success: true }
    } catch (err: unknown) {
      return { success: false, error: err instanceof Error ? err.message : String(err) }
    }
  })
}

app.whenReady().then(() => {
  nativeTheme.themeSource = 'light'
  let mainSession = sessionService.findMainSession(process.cwd())

  if (mainSession && !mainSession.name) {
    sessionService.nameSession(mainSession.filePath, 'main')
    mainSession = { ...mainSession, name: 'main' }
  }

  initPiBridge(mainSession?.filePath)
  registerIpcHandlers()
  createWindow()

  app.on('activate', () => {
    if (BrowserWindow.getAllWindows().length === 0) {
      createWindow()
    }
  })
})

app.on('window-all-closed', () => {
  if (process.platform !== 'darwin') {
    app.quit()
  }
})

app.on('before-quit', () => {
  piBridge?.stop().catch((err: Error) => {
    console.error('[PiSDKBridge] Error during shutdown:', err.message)
  })
})

import { useEffect, useState, useCallback } from 'react'
import { usePiRpc } from './hooks/usePiRpc'
import { useSessionManager } from './hooks/useSessionManager'
import ChatView from './components/ChatView'
import InputBar from './components/InputBar'
import SessionSidebar from './components/SessionSidebar'

function getDisplayName(session: { name: string | null; createdAt: string }): string {
  if (session.name) return session.name
  const d = new Date(session.createdAt)
  const month = d.toLocaleString('en', { month: 'short' })
  const day = d.getDate()
  const hh = String(d.getHours()).padStart(2, '0')
  const mm = String(d.getMinutes()).padStart(2, '0')
  return `${month} ${day} ${hh}:${mm}`
}

function App(): React.ReactElement {
  const { messages, isConnected, isStreaming, sendPrompt, abort, pendingUiRequests, respondToUiRequest, clearMessages, loadHistory, forkPoints, loadForkPoints, setOnAgentEnd } = usePiRpc()
  const { sessions, currentSession, forkAtEntry, switchSession, newSession, renameSession, deleteSession, getForkMessages, clearSession, refresh } = useSessionManager(isConnected)
  const [error, setError] = useState<string | null>(null)
  const [sidebarCollapsed, setSidebarCollapsed] = useState(false)
  const [activeSessionPath, setActiveSessionPath] = useState<string | null>(null)

  const activeSession = activeSessionPath
    ? sessions?.projects?.flatMap(p => p.allSessions).find(s => s.filePath === activeSessionPath)
    : currentSession

  const activeSessionName = activeSession ? getDisplayName(activeSession) : null

  async function handleConnect(): Promise<void> {
    setError(null)
    const result = await window.api.start()
    if (!result.ok && result.error) {
      setError(result.error)
    }
    refresh()
  }

  // Auto-start Pi on mount
  useEffect(() => {
    handleConnect()
  }, [])

  const handleSwitchSession = useCallback(async (sessionPath: string) => {
    setActiveSessionPath(sessionPath)
    clearMessages()
    await switchSession(sessionPath)
    await loadHistory()
    await loadForkPoints(sessionPath)
    await refresh()
  }, [clearMessages, switchSession, loadHistory, loadForkPoints, refresh])

  const handleNewSession = useCallback(async (name: string) => {
    const parentPath = currentSession?.filePath
    clearMessages()
    const result = await newSession(name, parentPath)
    if (result) await refresh()
  }, [clearMessages, newSession, currentSession, refresh])

  const handleForkAtEntry = useCallback(async (entryId: string, name: string) => {
    clearMessages()
    await forkAtEntry(entryId, name)
    await loadHistory()
    await refresh()
  }, [clearMessages, forkAtEntry, loadHistory, refresh])

  const handleClearSession = useCallback(async () => {
    clearMessages()
    const ok = await clearSession()
    if (ok) {
      clearMessages()
      await loadHistory()
      await refresh()
      setActiveSessionPath(null)
    }
  }, [clearMessages, clearSession, loadHistory, refresh])

  useEffect(() => {
    if (isConnected) {
      loadHistory()
    }
  }, [isConnected, loadHistory])

  useEffect(() => {
    if (isConnected && currentSession?.filePath) {
      loadForkPoints(currentSession.filePath)
    }
  }, [isConnected, currentSession?.filePath, loadForkPoints])

  useEffect(() => {
    setOnAgentEnd(() => refresh)
  }, [setOnAgentEnd, refresh])

  useEffect(() => {
    function handleKeyDown(e: KeyboardEvent): void {
      if (e.key === 'Escape' && isStreaming) {
        abort()
      }
    }
    window.addEventListener('keydown', handleKeyDown)
    return () => window.removeEventListener('keydown', handleKeyDown)
  }, [isStreaming, abort])

  useEffect(() => {
    const cleanup = window.api.onEvent((rawEvent) => {
      const evt = rawEvent as { type: string; error?: string; errorMessage?: string }
      if (evt.type === 'extension_error' && evt.error) {
        setError(`Extension error: ${evt.error}`)
      }
    })
    return cleanup
  }, [])

  return (
    <div className="flex h-screen w-screen overflow-hidden bg-white text-gray-900">
      <SessionSidebar
        sessions={sessions}
        currentSession={currentSession}
        onSwitchSession={handleSwitchSession}
        onNewSession={handleNewSession}
        onRenameSession={renameSession}
        onDeleteSession={deleteSession}
        isCollapsed={sidebarCollapsed}
        onToggleCollapse={() => setSidebarCollapsed(!sidebarCollapsed)}
      />

      <div className="flex flex-1 flex-col overflow-hidden">
        <div className="flex items-center justify-between border-b border-gray-200 bg-gray-50 px-4 pt-10 pb-2" style={{ WebkitAppRegion: 'drag' } as React.CSSProperties}>
          <div className="flex items-center gap-2" style={{ WebkitAppRegion: 'no-drag' } as React.CSSProperties}>
            {sidebarCollapsed && (
              <button
                onClick={() => setSidebarCollapsed(false)}
                className="rounded p-1 text-gray-500 hover:text-gray-700 hover:bg-gray-100 transition-colors"
                title="Show sessions"
              >
                <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                  <path strokeLinecap="round" strokeLinejoin="round" d="M4 6h16M4 12h16M4 18h16" />
                </svg>
              </button>
            )}
            <div className={`h-2 w-2 rounded-full ${isConnected ? 'bg-green-500' : 'bg-red-500'}`} />
            <span className="text-xs text-gray-600">
              {isConnected ? 'Pi Connected' : 'Pi Disconnected'}
            </span>
            {activeSessionName && (
              <>
                <span className="text-xs text-gray-700 font-medium border-l border-gray-300 pl-2">
                  {activeSessionName}
                </span>
                <button
                  onClick={handleClearSession}
                  className="rounded p-1 text-gray-400 hover:text-red-500 hover:bg-gray-100 transition-colors"
                  title="Clear conversation"
                >
                  <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                    <path strokeLinecap="round" strokeLinejoin="round" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                  </svg>
                </button>
              </>
            )}
            {isStreaming && (
              <span className="text-xs text-blue-600 animate-pulse">Streaming...</span>
            )}
            {error && (
              <span className="text-xs text-red-500" title={error}>Error</span>
            )}
          </div>
          <div className="flex items-center gap-2" style={{ WebkitAppRegion: 'no-drag' } as React.CSSProperties}>
            {!isConnected && (
              <button
                onClick={handleConnect}
                className="rounded bg-blue-600 px-3 py-1 text-xs font-medium text-white hover:bg-blue-500"
              >
                Connect to Pi
              </button>
            )}
            {isStreaming && (
              <button
                onClick={abort}
                className="rounded bg-red-600 px-3 py-1 text-xs font-medium text-white hover:bg-red-500"
              >
                Stop (Esc)
              </button>
            )}
          </div>
        </div>

        <ChatView
          messages={messages}
          pendingUiRequests={pendingUiRequests}
          respondToUiRequest={respondToUiRequest}
          onSendPrompt={sendPrompt}
          onForkAtEntry={handleForkAtEntry}
          getForkMessages={getForkMessages}
          forkPoints={forkPoints}
        />

        <InputBar onSend={sendPrompt} disabled={!isConnected || isStreaming} />
      </div>
    </div>
  )
}

export default App

import { useEffect, useRef, useState, useCallback, useImperativeHandle, forwardRef } from 'react'
import { Canvas, Rect, Circle, Line, IText, FabricImage, FabricObject } from 'fabric'
import type { Annotation } from '../types/message'

type AnnotationTool = 'rect' | 'circle' | 'arrow' | 'text' | 'select'

interface ImageAnnotatorProps {
  src: string
  alt?: string
  annotations: Annotation[]
  onAnnotationsChange: (annotations: Annotation[]) => void
  isActive: boolean
}

export interface ImageAnnotatorHandle {
  getAnnotatedImage: () => { dataUrl: string; description: string } | null
}

export const ImageAnnotator = forwardRef<ImageAnnotatorHandle, ImageAnnotatorProps>(
  function ImageAnnotator({ src, alt, annotations, onAnnotationsChange, isActive }, ref) {
    const containerRef = useRef<HTMLDivElement>(null)
    const canvasRef = useRef<HTMLCanvasElement>(null)
    const fabricRef = useRef<Canvas | null>(null)
    const imgRef = useRef<HTMLImageElement | null>(null)
    const scaleRef = useRef<number>(1)
    const [activeTool, setActiveTool] = useState<AnnotationTool>('rect')
    const [isDrawing, setIsDrawing] = useState(false)
    const drawStartRef = useRef<{ x: number; y: number } | null>(null)
    const currentShapeRef = useRef<FabricObject | null>(null)

    useImperativeHandle(ref, () => ({
      getAnnotatedImage: () => {
        const canvas = fabricRef.current
        if (!canvas) return null

        const dataUrl = canvas.toDataURL({ format: 'png' })
        const description = annotationsToPrompt(annotations, alt ?? 'image')
        return { dataUrl, description }
      }
    }), [annotations, alt])

    useEffect(() => {
      if (!isActive || !canvasRef.current || !containerRef.current) return

      const img = new Image()
      img.crossOrigin = 'anonymous'
      img.onload = () => {
        imgRef.current = img
        const containerWidth = containerRef.current!.clientWidth
        const scale = containerWidth / img.width
        scaleRef.current = scale
        const displayWidth = containerWidth
        const displayHeight = img.height * scale

        const canvas = new Canvas(canvasRef.current!, {
          width: displayWidth,
          height: displayHeight,
          selection: false,
        })

        // Fabric v6 uses FabricImage.fromURL instead of v5's canvas.setBackgroundImage()
        FabricImage.fromURL(src, { crossOrigin: 'anonymous' }).then((fabricImg) => {
          fabricImg.set({
            scaleX: scale,
            scaleY: scale,
            originX: 'left',
            originY: 'top',
          })
          canvas.backgroundImage = fabricImg
          canvas.renderAll()
        }).catch(() => {
          FabricImage.fromURL(src).then((fabricImg) => {
            fabricImg.set({
              scaleX: scale,
              scaleY: scale,
              originX: 'left',
              originY: 'top',
            })
            canvas.backgroundImage = fabricImg
            canvas.renderAll()
          })
        })

        fabricRef.current = canvas
      }
      img.src = src

      return () => {
        const canvas = fabricRef.current
        if (canvas) {
          canvas.dispose()
          fabricRef.current = null
        }
      }
    }, [isActive, src])

    useEffect(() => {
      const canvas = fabricRef.current
      if (!canvas || !isActive) return

      const onMouseDown = (opt: { e: MouseEvent }) => {
        if (activeTool === 'select') return
        const point = getCanvasPoint(opt.e)
        if (!point) return

        setIsDrawing(true)
        drawStartRef.current = point

        let shape: FabricObject

        switch (activeTool) {
          case 'rect':
            shape = new Rect({
              left: point.x,
              top: point.y,
              width: 0,
              height: 0,
              fill: 'transparent',
              stroke: '#ef4444',
              strokeWidth: 2,
              strokeUniform: true,
            })
            break
          case 'circle':
            shape = new Circle({
              left: point.x,
              top: point.y,
              radius: 0,
              fill: 'transparent',
              stroke: '#ef4444',
              strokeWidth: 2,
              strokeUniform: true,
            })
            break
          case 'arrow':
            shape = new Line([point.x, point.y, point.x, point.y], {
              stroke: '#ef4444',
              strokeWidth: 2,
              strokeUniform: true,
            })
            break
          case 'text':
            shape = new IText('Label', {
              left: point.x,
              top: point.y,
              fontSize: 16,
              fill: '#ef4444',
              fontFamily: 'sans-serif',
            })
            canvas.add(shape)
            canvas.setActiveObject(shape)
            setIsDrawing(false)
            drawStartRef.current = null
            return
          default:
            return
        }

        canvas.add(shape)
        currentShapeRef.current = shape
      }

      const onMouseMove = (opt: { e: MouseEvent }) => {
        if (!isDrawing || !drawStartRef.current || !currentShapeRef.current || !fabricRef.current) return
        const point = getCanvasPoint(opt.e)
        if (!point) return

        const shape = currentShapeRef.current
        const start = drawStartRef.current

        if (shape instanceof Rect) {
          const left = Math.min(start.x, point.x)
          const top = Math.min(start.y, point.y)
          shape.set({
            left,
            top,
            width: Math.abs(point.x - start.x),
            height: Math.abs(point.y - start.y),
          })
        } else if (shape instanceof Circle) {
          const radius = Math.sqrt(
            Math.pow(point.x - start.x, 2) + Math.pow(point.y - start.y, 2)
          ) / 2
          shape.set({
            left: (start.x + point.x) / 2 - radius,
            top: (start.y + point.y) / 2 - radius,
            radius,
          })
        } else if (shape instanceof Line) {
          shape.set({ x2: point.x, y2: point.y })
        }

        fabricRef.current.renderAll()
      }

      const onMouseUp = () => {
        setIsDrawing(false)
        drawStartRef.current = null
        currentShapeRef.current = null
        exportAnnotations()
      }

      canvas.on('mouse:down', onMouseDown)
      canvas.on('mouse:move', onMouseMove)
      canvas.on('mouse:up', onMouseUp)

      canvas.selection = activeTool === 'select'
      canvas.defaultCursor = activeTool === 'select' ? 'default' : 'crosshair'

      canvas.getObjects().forEach((obj) => {
        obj.selectable = activeTool === 'select'
        obj.evented = activeTool === 'select'
      })

      return () => {
        canvas.off('mouse:down', onMouseDown)
        canvas.off('mouse:move', onMouseMove)
        canvas.off('mouse:up', onMouseUp)
      }
    }, [isActive, activeTool, isDrawing])

    const getCanvasPoint = useCallback((e: MouseEvent) => {
      const canvas = fabricRef.current
      if (!canvas) return null
      const pointer = canvas.getScenePoint(e)
      return { x: pointer.x, y: pointer.y }
    }, [])

    const exportAnnotations = useCallback(() => {
      const canvas = fabricRef.current
      if (!canvas) return

      const img = imgRef.current
      if (!img) return

      const scaleX = img.width / canvas.width
      const scaleY = img.height / canvas.height

      const newAnnotations: Annotation[] = []
      const objects = canvas.getObjects()

      for (const obj of objects) {
        const normX = (obj.left ?? 0) * scaleX / img.width
        const normY = (obj.top ?? 0) * scaleY / img.height

        if (obj instanceof Rect) {
          newAnnotations.push({
            id: crypto.randomUUID(),
            type: 'rect',
            coords: [
              normX,
              normY,
              (obj.width ?? 0) * scaleX / img.width,
              (obj.height ?? 0) * scaleY / img.height,
            ],
            color: obj.stroke as string,
          })
        } else if (obj instanceof Circle) {
          newAnnotations.push({
            id: crypto.randomUUID(),
            type: 'circle',
            coords: [
              normX,
              normY,
              ((obj.radius ?? 0) * 2 * scaleX) / img.width,
            ],
            color: obj.stroke as string,
          })
        } else if (obj instanceof Line) {
          const x2 = ((obj.x2 ?? 0) * scaleX) / img.width
          const y2 = ((obj.y2 ?? 0) * scaleY) / img.height
          newAnnotations.push({
            id: crypto.randomUUID(),
            type: 'arrow',
            coords: [normX, normY, x2, y2],
            color: obj.stroke as string,
          })
        } else if (obj instanceof IText) {
          newAnnotations.push({
            id: crypto.randomUUID(),
            type: 'text',
            coords: [normX, normY],
            label: obj.text ?? '',
            color: obj.fill as string,
          })
        }
      }

      onAnnotationsChange(newAnnotations)
    }, [onAnnotationsChange])

    const handleClear = useCallback(() => {
      const canvas = fabricRef.current
      if (!canvas) return
      canvas.clear()
      const img = imgRef.current
      if (img) {
        FabricImage.fromURL(src).then((fabricImg) => {
          fabricImg.set({
            scaleX: scaleRef.current,
            scaleY: scaleRef.current,
            originX: 'left',
            originY: 'top',
          })
          canvas.backgroundImage = fabricImg
          canvas.renderAll()
        })
      }
      onAnnotationsChange([])
    }, [src, onAnnotationsChange])

    if (!isActive) {
      return null
    }

    return (
      <div ref={containerRef} className="relative">
        <div className="absolute top-2 left-2 z-10 flex gap-1 rounded bg-white/90 shadow-sm border border-gray-200 p-1">
          {(['select', 'rect', 'circle', 'arrow', 'text'] as AnnotationTool[]).map((tool) => (
            <button
              key={tool}
              onClick={() => setActiveTool(tool)}
              className={`rounded px-2 py-1 text-xs font-medium ${
                activeTool === tool
                  ? 'bg-blue-600 text-white'
                  : 'bg-gray-100 text-gray-700 hover:bg-gray-200'
              }`}
            >
              {tool === 'select' ? 'Select' : tool === 'rect' ? 'Rect' : tool === 'circle' ? 'Circle' : tool === 'arrow' ? 'Arrow' : 'Text'}
            </button>
          ))}
          <button
            onClick={handleClear}
            className="rounded bg-red-700 px-2 py-1 text-xs font-medium text-white hover:bg-red-600"
          >
            Clear
          </button>
        </div>
        <canvas ref={canvasRef} />
      </div>
    )
  }
)

function annotationsToPrompt(annotations: Annotation[], imageContext: string): string {
  if (annotations.length === 0) return `User annotated "${imageContext}" with no specific markings.`

  const parts = annotations.map((a) => {
    const pos = `position [${a.coords.map((c) => Math.round(c * 100))}%]`
    switch (a.type) {
      case 'rect':
        return `${pos} drew a rectangle${a.label ? `, labeled: "${a.label}"` : ''}`
      case 'circle':
        return `${pos} drew a circle${a.label ? `, labeled: "${a.label}"` : ''}`
      case 'arrow':
        return `${pos} drew an arrow${a.label ? `, labeled: "${a.label}"` : ''}`
      case 'text':
        return `${pos} wrote: "${a.label ?? ''}"`
    }
  })

  return `User annotated "${imageContext}":\n${parts.join('\n')}`
}

export { annotationsToPrompt }

import { useState } from 'react'
import type { ActionBlock } from '../types/message'

interface ActionBlockRendererProps {
  block: ActionBlock
  onRespond: (response: Record<string, unknown>) => void
}

export function ActionBlockRenderer({ block, onRespond }: ActionBlockRendererProps) {
  switch (block.actionType) {
    case 'select':
      return <SelectAction block={block} onRespond={onRespond} />
    case 'confirm':
      return <ConfirmAction block={block} onRespond={onRespond} />
    case 'input':
      return <InputAction block={block} onRespond={onRespond} />
  }
}

function SelectAction({ block, onRespond }: ActionBlockRendererProps) {
  const [selected, setSelected] = useState<string | null>(null)

  if (!block.options || block.options.length === 0) return null

  return (
    <div className="rounded-lg border border-amber-300 bg-amber-50 p-3">
      <div className="mb-2 text-sm font-medium text-amber-800">{block.label}</div>
      <div className="flex flex-wrap gap-2">
        {block.options.map((opt) => (
          <button
            key={opt.id}
            onClick={() => {
              setSelected(opt.id)
              onRespond({ value: opt.label })
            }}
            className={`rounded-lg border px-4 py-2 text-sm transition-colors ${
              selected === opt.id
                ? 'border-amber-500 bg-amber-600 text-white'
                : 'border-gray-300 bg-white text-gray-700 hover:border-gray-400 hover:bg-gray-50'
            }`}
          >
            {opt.label}
            {opt.description && (
              <span className="ml-1 text-xs opacity-60">- {opt.description}</span>
            )}
          </button>
        ))}
      </div>
    </div>
  )
}

function ConfirmAction({ block, onRespond }: ActionBlockRendererProps) {
  return (
    <div className="rounded-lg border border-amber-300 bg-amber-50 p-3">
      <div className="mb-2 text-sm font-medium text-amber-800">{block.label}</div>
      <div className="flex gap-2">
        <button
          onClick={() => onRespond({ confirmed: true })}
          className="rounded-lg bg-green-600 px-4 py-2 text-sm font-medium text-white hover:bg-green-500"
        >
          Confirm
        </button>
        <button
          onClick={() => onRespond({ cancelled: true as const })}
          className="rounded-lg bg-red-600 px-4 py-2 text-sm font-medium text-white hover:bg-red-500"
        >
          Cancel
        </button>
      </div>
    </div>
  )
}

function InputAction({ block, onRespond }: ActionBlockRendererProps) {
  const [value, setValue] = useState('')

  return (
    <div className="rounded-lg border border-amber-300 bg-amber-50 p-3">
      <div className="mb-2 text-sm font-medium text-amber-800">{block.label}</div>
      <div className="flex gap-2">
        <input
          type="text"
          value={value}
          onChange={(e) => setValue(e.target.value)}
          onKeyDown={(e) => {
            if (e.key === 'Enter' && value.trim()) {
              onRespond({ value: value.trim() })
            }
          }}
          placeholder="Type your response..."
          className="flex-1 rounded-lg border border-gray-300 bg-white px-3 py-2 text-sm text-gray-900 placeholder-gray-400 focus:outline-none focus:ring-1 focus:ring-amber-500"
        />
        <button
          onClick={() => {
            if (value.trim()) onRespond({ value: value.trim() })
          }}
          disabled={!value.trim()}
          className="rounded-lg bg-amber-600 px-4 py-2 text-sm font-medium text-white hover:bg-amber-500 disabled:opacity-50"
        >
          Send
        </button>
      </div>
    </div>
  )
}

import { useState, useCallback, useEffect, useRef } from 'react'
import ReactMarkdown from 'react-markdown'
import remarkGfm from 'remark-gfm'
import type {
  ChatMessage,
  ContentBlock,
  TextBlock,
  ToolCallBlock,
  ToolResultBlock,
  ImageBlock,
  HtmlBlock,
  Annotation,
} from '../types/message'
import type { ForkableMessage, ForkPoint } from '../types/session'
import { ImageAnnotator, annotationsToPrompt } from './ImageAnnotator'
import type { ImageAnnotatorHandle } from './ImageAnnotator'

interface ChatViewProps {
  messages: ChatMessage[]
  onSendPrompt: (text: string, images?: { data: string; mimeType: string }[]) => void
  pendingUiRequests: Array<{ id: string; method: string; [key: string]: unknown }>
  respondToUiRequest: (requestId: string, response: Record<string, unknown>) => void
  onForkAtEntry: (entryId: string, name: string) => void
  getForkMessages: () => Promise<ForkableMessage[]>
  forkPoints: ForkPoint[]
}

function TextBlockRenderer({ block }: { block: TextBlock }): React.ReactElement {
  return (
    <div className="prose prose-sm max-w-none">
      <ReactMarkdown remarkPlugins={[remarkGfm]}>{block.content}</ReactMarkdown>
    </div>
  )
}

function ToolCallRenderer({ block }: { block: ToolCallBlock }): React.ReactElement {
  const statusColors: Record<ToolCallBlock['status'], string> = {
    pending: 'text-gray-500',
    running: 'text-yellow-600',
    completed: 'text-green-600',
    error: 'text-red-500',
  }

  const statusIcons: Record<ToolCallBlock['status'], string> = {
    pending: '\u25CB',
    running: '\u25D4',
    completed: '\u25CF',
    error: '\u2717',
  }

  return (
    <details className="rounded border border-gray-200 bg-gray-50">
      <summary className="cursor-pointer px-3 py-2 text-sm">
        <span className={statusColors[block.status]}>{statusIcons[block.status]}</span>
        {' '}
        <span className="font-mono text-xs text-gray-700">{block.toolName}</span>
        {block.toolName === 'bash' && block.args.command && (
          <span className="ml-2 font-mono text-xs text-gray-400">
            {String(block.args.command).substring(0, 60)}
            {String(block.args.command).length > 60 ? '...' : ''}
          </span>
        )}
      </summary>
      <div className="border-t border-gray-200 px-3 py-2">
        <pre className="overflow-x-auto text-xs text-gray-600">
          {JSON.stringify(block.args, null, 2)}
        </pre>
      </div>
    </details>
  )
}

function ToolResultRenderer({ block }: { block: ToolResultBlock }): React.ReactElement {
  return (
    <div className="space-y-2 rounded border border-gray-200 bg-gray-50/50 px-3 py-2">
      {block.content.map((child, i) => {
        if (child.type === 'text') {
          return (
            <pre key={i} className="overflow-x-auto whitespace-pre-wrap text-xs text-gray-600">
              {(child as TextBlock).content}
            </pre>
          )
        }
        if (child.type === 'image') {
          return <ImageBlockRenderer key={i} block={child as ImageBlock} />
        }
        if (child.type === 'html') {
          return <HtmlBlockRenderer key={i} block={child as HtmlBlock} />
        }
        return null
      })}
    </div>
  )
}

function HtmlBlockRenderer({ block }: { block: HtmlBlock }): React.ReactElement {
  const [expanded, setExpanded] = useState(true)
  const iframeRef = useRef<HTMLIFrameElement>(null)

  const handleLoad = useCallback(() => {
    if (!iframeRef.current) return
    const doc = iframeRef.current.contentDocument
    if (!doc?.body) return
    const height = doc.body.scrollHeight
    iframeRef.current.style.height = `${Math.min(Math.max(height, 100), 600)}px`
  }, [])

  return (
    <div className="my-2 overflow-hidden rounded border border-gray-200">
      <div className="flex items-center justify-between bg-gray-100 px-3 py-1.5">
        <span className="text-xs font-medium text-gray-500">
          {block.title ?? 'HTML Preview'}
        </span>
        <button
          onClick={() => setExpanded(!expanded)}
          className="text-xs text-gray-400 hover:text-gray-600"
        >
          {expanded ? 'Collapse' : 'Expand'}
        </button>
      </div>
      {expanded && (
        <iframe
          ref={iframeRef}
          srcDoc={block.content}
          sandbox="allow-scripts allow-same-origin"
          onLoad={handleLoad}
          className="w-full border-0 bg-white"
          style={{ height: '300px' }}
          title={block.title ?? 'HTML Preview'}
        />
      )}
    </div>
  )
}

interface AnnotatableImageBlockProps {
  block: ImageBlock
  messageId: string
  blockIndex: number
  isAnnotating: boolean
  onEnterAnnotation: () => void
  onExitAnnotation: () => void
  onSendFeedback: (description: string, imageData: string) => void
}

function AnnotatableImageBlock({
  block,
  messageId,
  blockIndex,
  isAnnotating,
  onEnterAnnotation,
  onExitAnnotation,
  onSendFeedback,
}: AnnotatableImageBlockProps): React.ReactElement {
  const [annotations, setAnnotations] = useState<Annotation[]>([])
  const [isFullscreen, setIsFullscreen] = useState(false)
  const [zoom, setZoom] = useState(1)
  const annotatorRef = useRef<ImageAnnotatorHandle>(null)

  void messageId
  void blockIndex

  const handleWheel = useCallback((e: React.WheelEvent) => {
    e.preventDefault()
    setZoom((prev) => Math.max(0.25, Math.min(4, prev + (e.deltaY > 0 ? -0.15 : 0.15))))
  }, [])

  useEffect(() => {
    if (!isFullscreen) return
    const handler = (e: KeyboardEvent) => {
      if (e.key === 'Escape') {
        setIsFullscreen(false)
        setZoom(1)
      }
    }
    window.addEventListener('keydown', handler)
    return () => window.removeEventListener('keydown', handler)
  }, [isFullscreen])

  const handleSendFeedback = useCallback(() => {
    if (!annotatorRef.current) return
    const result = annotatorRef.current.getAnnotatedImage()
    if (!result) return

    const base64Match = result.dataUrl.match(/^data:image\/png;base64,(.+)$/)
    if (!base64Match) return

    onSendFeedback(result.description, base64Match[1])
    onExitAnnotation()
  }, [onSendFeedback, onExitAnnotation])

  if (isAnnotating) {
    return (
      <div className="my-2 overflow-hidden rounded border border-blue-600">
        <ImageAnnotator
          ref={annotatorRef}
          src={block.src}
          alt={block.alt}
          annotations={annotations}
          onAnnotationsChange={setAnnotations}
          isActive={true}
        />
        <div className="flex items-center justify-between border-t border-blue-600 bg-gray-100 px-3 py-2">
          <span className="text-xs text-gray-600">
            {annotations.length} annotation{annotations.length !== 1 ? 's' : ''}
          </span>
          <div className="flex gap-2">
            <button
              onClick={onExitAnnotation}
              className="rounded bg-gray-200 px-3 py-1 text-xs font-medium text-gray-700 hover:bg-gray-300"
            >
              Cancel
            </button>
            <button
              onClick={handleSendFeedback}
              className="rounded bg-blue-600 px-3 py-1 text-xs font-medium text-white hover:bg-blue-500"
            >
              Send Feedback
            </button>
          </div>
        </div>
      </div>
    )
  }

  if (isFullscreen) {
    return (
      <div
        className="fixed inset-0 z-50 flex items-center justify-center bg-black/50"
        onClick={() => {
          setIsFullscreen(false)
          setZoom(1)
        }}
      >
        <img
          src={block.src}
          alt={block.alt ?? 'image'}
          style={{ transform: `scale(${zoom})`, transformOrigin: 'center' }}
          className="max-h-[90vh] max-w-[90vw] cursor-zoom-out transition-transform"
          onWheel={handleWheel}
          onClick={(e) => e.stopPropagation()}
        />
        <div className="absolute bottom-4 right-4 flex gap-2">
          <button
            onClick={(e) => {
              e.stopPropagation()
              setZoom((z) => Math.min(4, z + 0.25))
            }}
            className="rounded bg-gray-800/80 px-3 py-1 text-sm text-white hover:bg-gray-700"
          >
            +
          </button>
          <span className="rounded bg-gray-800/80 px-3 py-1 text-sm text-white">
            {Math.round(zoom * 100)}%
          </span>
          <button
            onClick={(e) => {
              e.stopPropagation()
              setZoom((z) => Math.max(0.25, z - 0.25))
            }}
            className="rounded bg-gray-800/80 px-3 py-1 text-sm text-white hover:bg-gray-700"
          >
            -
          </button>
          <button
            onClick={(e) => {
              e.stopPropagation()
              setIsFullscreen(false)
              setZoom(1)
            }}
            className="rounded bg-red-800/80 px-3 py-1 text-sm text-white hover:bg-red-700"
          >
            ESC
          </button>
        </div>
      </div>
    )
  }

  return (
    <div className="my-2 overflow-hidden rounded border border-gray-200">
      <div className="relative group">
        <img
          src={block.src}
          alt={block.alt ?? 'image'}
          className="max-w-full cursor-zoom-in transition-opacity hover:opacity-90"
          onClick={() => setIsFullscreen(true)}
          loading="lazy"
        />
        <button
          onClick={onEnterAnnotation}
          className="absolute top-2 right-2 rounded bg-blue-600/90 px-2 py-1 text-xs font-medium text-white opacity-0 transition-opacity hover:bg-blue-500 group-hover:opacity-100"
        >
          Annotate
        </button>
      </div>
      {block.alt && (
        <div className="border-t border-gray-200 bg-gray-50 px-2 py-1 text-xs text-gray-500">
          {block.alt}
        </div>
      )}
    </div>
  )
}

function ContentBlockRenderer({
  block,
  messageId,
  blockIndex,
  annotatingTarget,
  onEnterAnnotation,
  onExitAnnotation,
  onSendFeedback,
}: {
  block: ContentBlock
  messageId: string
  blockIndex: number
  annotatingTarget: { messageId: string; blockIndex: number } | null
  onEnterAnnotation: (messageId: string, blockIndex: number) => void
  onExitAnnotation: () => void
  onSendFeedback: (description: string, imageData: string) => void
}): React.ReactElement | null {
  switch (block.type) {
    case 'text':
      return <TextBlockRenderer block={block} />
    case 'tool_call':
      return <ToolCallRenderer block={block} />
    case 'tool_result':
      return <ToolResultRenderer block={block} />
    case 'image':
      return (
        <AnnotatableImageBlock
          block={block}
          messageId={messageId}
          blockIndex={blockIndex}
          isAnnotating={
            annotatingTarget !== null &&
            annotatingTarget.messageId === messageId &&
            annotatingTarget.blockIndex === blockIndex
          }
          onEnterAnnotation={() => onEnterAnnotation(messageId, blockIndex)}
          onExitAnnotation={onExitAnnotation}
          onSendFeedback={onSendFeedback}
        />
      )
    case 'action':
      return <div className="text-xs text-yellow-600">[Action: {block.actionType}]</div>
    case 'html':
      return <HtmlBlockRenderer block={block} />
    default:
      return null
  }
}

function ForkNameInput({
  onForkAtEntry,
  onClose,
  defaultEntryId,
}: {
  onForkAtEntry: (entryId: string, name: string) => void
  onClose: () => void
  defaultEntryId: string
}): React.ReactElement {
  const popoverRef = useRef<HTMLDivElement>(null)
  const [forkName, setForkName] = useState('')

  useEffect(() => {
    function handleClickOutside(e: MouseEvent): void {
      if (popoverRef.current && !popoverRef.current.contains(e.target as Node)) {
        onClose()
      }
    }
    document.addEventListener('mousedown', handleClickOutside)
    return () => document.removeEventListener('mousedown', handleClickOutside)
  }, [onClose])

  const handleConfirm = useCallback(() => {
    if (forkName.trim()) {
      onForkAtEntry(defaultEntryId, forkName.trim())
      onClose()
    }
  }, [forkName, defaultEntryId, onForkAtEntry, onClose])

  return (
    <div
      ref={popoverRef}
      className="absolute right-0 top-8 z-30 w-64 rounded-lg border border-gray-200 bg-white shadow-xl"
    >
      <div className="px-3 py-2 space-y-1.5">
        <input
          autoFocus
          value={forkName}
          onChange={(e) => setForkName(e.target.value)}
          onKeyDown={(e) => {
            if (e.key === 'Enter') handleConfirm()
            if (e.key === 'Escape') onClose()
          }}
          placeholder="Fork session name"
          className="w-full rounded border border-gray-300 bg-white px-2 py-1 text-xs text-gray-900 outline-none focus:border-blue-500"
        />
        <button
          onClick={handleConfirm}
          disabled={!forkName.trim()}
          className="w-full rounded bg-blue-600 px-2 py-1 text-xs font-medium text-white hover:bg-blue-500 disabled:opacity-40 disabled:cursor-not-allowed"
        >
          Fork from here
        </button>
      </div>
    </div>
  )
}

function ChatView({ messages, onSendPrompt, pendingUiRequests, respondToUiRequest, onForkAtEntry, getForkMessages, forkPoints }: ChatViewProps): React.ReactElement {
  const bottomRef = useRef<HTMLDivElement>(null)
  const [annotatingTarget, setAnnotatingTarget] = useState<{
    messageId: string
    blockIndex: number
  } | null>(null)
  const [forkInputMessageId, setForkInputMessageId] = useState<string | null>(null)
  const [forkEntryId, setForkEntryId] = useState<string | null>(null)

  const handleEnterAnnotation = useCallback((messageId: string, blockIndex: number) => {
    setAnnotatingTarget({ messageId, blockIndex })
  }, [])

  const handleExitAnnotation = useCallback(() => {
    setAnnotatingTarget(null)
  }, [])

  const handleSendFeedback = useCallback(
    (description: string, imageData: string) => {
      onSendPrompt(description, [{ data: imageData, mimeType: 'image/png' }])
      setAnnotatingTarget(null)
    },
    [onSendPrompt],
  )

  const handleForkClick = useCallback(async (messageId: string, piEntryId: string | undefined) => {
    if (forkInputMessageId === messageId) {
      setForkInputMessageId(null)
      setForkEntryId(null)
      return
    }
    if (piEntryId) {
      setForkEntryId(piEntryId)
    } else {
      const msgs = await getForkMessages()
      const lastMsg = msgs[msgs.length - 1]
      setForkEntryId(lastMsg?.entryId ?? null)
    }
    setForkInputMessageId(messageId)
  }, [forkInputMessageId, getForkMessages])

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: 'smooth' })
  }, [messages])

  return (
    <div className="flex-1 overflow-y-auto bg-white px-4 py-6">
      {messages.length === 0 ? (
        <div className="flex h-full items-center justify-center">
          <div className="text-center">
            <p className="text-lg text-gray-400">Start a conversation with Pi</p>
            <p className="mt-2 text-sm text-gray-400">Type a message below or connect to Pi first</p>
          </div>
        </div>
      ) : (
        <div className="mx-auto max-w-3xl space-y-4">
          {messages.map((msg) => {
            const msgForkPoints = forkPoints.filter((fp) => fp.entryId === msg.piEntryId)

            return (
              <div
                key={msg.id}
                className={`group relative rounded-lg px-4 py-3 ${
                  msg.role === 'user'
                    ? 'bg-blue-50 ml-8'
                    : 'bg-gray-50 mr-4'
                }`}
              >
                <div className="mb-1 flex items-center justify-between">
                  <span className="text-xs font-medium text-gray-500">
                    {msg.role === 'user' ? 'You' : 'Pi'}
                  </span>
                  {msg.role === 'user' && (
                    <div className="relative">
                      <button
                        onClick={() => handleForkClick(msg.id, msg.piEntryId)}
                        className="rounded px-2 py-0.5 text-xs text-gray-400 opacity-0 transition-opacity hover:text-gray-600 hover:bg-gray-100 group-hover:opacity-100"
                      >
                        Fork
                      </button>
                      {forkInputMessageId === msg.id && forkEntryId && (
                        <ForkNameInput
                          onForkAtEntry={onForkAtEntry}
                          onClose={() => { setForkInputMessageId(null); setForkEntryId(null) }}
                          defaultEntryId={forkEntryId}
                        />
                      )}
                    </div>
                  )}
                </div>
                <div className="space-y-2">
                  {msg.blocks.map((block, i) => (
                    <ContentBlockRenderer
                      key={i}
                      block={block}
                      messageId={msg.id}
                      blockIndex={i}
                      annotatingTarget={annotatingTarget}
                      onEnterAnnotation={handleEnterAnnotation}
                      onExitAnnotation={handleExitAnnotation}
                      onSendFeedback={handleSendFeedback}
                    />
                  ))}
                </div>
                {msgForkPoints.length > 0 && (
                  <div className="mt-2 flex flex-wrap gap-1.5 border-t border-gray-200/50 pt-2">
                    {msgForkPoints.map((fp, idx) => (
                      <span
                        key={idx}
                        className="inline-flex items-center gap-1 rounded-full bg-purple-100 px-2 py-0.5 text-[10px] text-purple-700"
                      >
                        <svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                          <path strokeLinecap="round" strokeLinejoin="round" d="M13 17h8m0 0V9m0 8l-8-8-4 4-6-6" />
                        </svg>
                        forked: {fp.childName || '(unnamed)'}
                      </span>
                    ))}
                  </div>
                )}
              </div>
            )
          })}
          <div ref={bottomRef} />
        </div>
      )}
    </div>
  )
}

